data.updated_code:
app.get("/api/stock/:symbol", async (req, res) => {
  try {
    const symbol = req.params.symbol.toUpperCase();

    if (USE_MOCK) {
      const mock = generateMockData(symbol);
      const latest = mock.data[mock.data.length - 1];
      mock.currentPrice = latest ? latest.close : null;
      return res.json(mock);
    }

    const data = await yahooFinance.chart(symbol, {
      period1: "2024-01-01",
      interval: "1d",
    });
    const quotes = data.quotes;

    const companyName = data.meta?.shortName || symbol;

    const response = {
      ticker: symbol,
      name: companyName,
      data: quotes.map((q) => ({
        date: q.date,
        close: q.close,
        volume: q.volume,
      })),
      currentPrice: quotes.length > 0 ? quotes[quotes.length - 1].close : null,
    };

    console.log(response);
    res.json(response);
  } catch (err) {
    console.error(err);
    res.status(500).send("Error fetching stock data");
  }
});

